<template><el-tag :type="tagType" effect="light" round>{{ label }}</el-tag></template><script setup>import { computed } from 'vue'; import { applicationStageLabelMap, jobStatusLabelMap } from '@/constants/status'; const props = defineProps({ status: { type: String, default: '' }, mode: { type: String, default: 'application' } }); const labelMap = { application: applicationStageLabelMap, job: jobStatusLabelMap, review: { PENDING: '\u5f85\u8bc4\u5ba1', PLANNED: '\u5f85\u5b89\u6392', APPROVED: '\u901a\u8fc7', REJECTED: '\u6dd8\u6c70' } }; const typeMap = { APPLIED:'info', SCREENING:'warning', INTERVIEW:'primary', OFFER:'success', REJECTED:'danger', WITHDRAWN:'info', OPEN:'success', DRAFT:'warning', CLOSED:'info', PENDING:'warning', PLANNED:'primary', APPROVED:'success' }; const label = computed(() => labelMap[props.mode]?.[props.status] || props.status || '\u672a\u8bbe\u7f6e'); const tagType = computed(() => typeMap[props.status] || 'info')</script>
